import sys

def solve(data: str) -> str:
    values = list(map(float, data.split())); centers = [min(values), max(values)]
    for _ in range(100):
        groups = [[], []]
        for value in values:
            index = 0 if abs(value-centers[0]) <= abs(value-centers[1]) else 1
            groups[index].append(value)
        updated = [sum(group)/len(group) if group else centers[index] for index,group in enumerate(groups)]
        if all(abs(a-b) < 1e-12 for a,b in zip(updated,centers)):
            break
        centers = updated
    centers.sort()
    return f"{centers[0]:.1f} {centers[1]:.1f}"

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
